import{_ as e,a as t,b as i,c as n}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as d,o as r,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Menambahkan WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/webdav.md","filePath":"id-ID/upload/webdav.md","lastUpdated":1781962217000}'),o={name:"id-ID/upload/webdav.md"};function u(c,a,p,h,m,k){return r(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="menambahkan-webdav-channel" tabindex="-1">Menambahkan WebDAV Channel <a class="header-anchor" href="#menambahkan-webdav-channel" aria-label="Permalink to &quot;Menambahkan WebDAV Channel&quot;">​</a></h1><h2 id="paling-cocok-untuk" tabindex="-1">Paling Cocok Untuk <a class="header-anchor" href="#paling-cocok-untuk" aria-label="Permalink to &quot;Paling Cocok Untuk&quot;">​</a></h2><p>Gunakan WebDAV channel saat:</p><ul><li>Anda memiliki NAS, cloud drive, atau object storage service yang menyediakan WebDAV endpoint.</li><li>Anda ingin uploaded images disimpan di WebDAV directory milik sendiri.</li><li>Anda ingin credentials disimpan di tabel D1 <code>upload_channels</code>, bukan terekspos lama di frontend.</li></ul><h2 id="yang-perlu-disiapkan-sebelum-mulai" tabindex="-1">Yang Perlu Disiapkan Sebelum Mulai <a class="header-anchor" href="#yang-perlu-disiapkan-sebelum-mulai" aria-label="Permalink to &quot;Yang Perlu Disiapkan Sebelum Mulai&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV URL, misalnya <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Digunakan untuk sign in ke WebDAV service.</td></tr><tr><td>Password</td><td>Digunakan untuk sign in ke WebDAV service.</td></tr><tr><td>Authentication mode</td><td>Default adalah <code>Basic</code>. Gunakan <code>Digest</code> atau auto negotiation hanya jika server memerlukannya.</td></tr><tr><td>Storage directory</td><td>Directory untuk menyimpan files. Default adalah <code>imgbed</code>.</td></tr></tbody></table><h2 id="di-mana-menambahkannya" tabindex="-1">Di Mana Menambahkannya <a class="header-anchor" href="#di-mana-menambahkannya" aria-label="Permalink to &quot;Di Mana Menambahkannya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Masuk ke Upload Settings.</li><li>Klik Add Channel di kanan atas.</li><li>Pilih <code>WebDAV</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali untuk WebDAV channel, misalnya <code>koofr</code> atau <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>Full WebDAV endpoint, termasuk <code>https://</code>.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>Biasanya <code>Basic</code>; gunakan <code>Digest</code> jika server membutuhkan digest authentication.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Directory tempat files disimpan. Default adalah <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-buat-app-password" tabindex="-1">1. Buat App Password <a class="header-anchor" href="#_1-buat-app-password" aria-label="Permalink to &quot;1. Buat App Password&quot;">​</a></h3><p>Buka account security settings, cari application passwords, lalu buat app password baru.</p><p><img src="'+e+'" alt="Create an app password" loading="lazy"></p><p>Setelah dibuat, copy dan simpan app password baru. Biasanya password ini hanya ditampilkan sekali.</p><p><img src="'+t+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-isi-webdav-configuration-di-imgbed" tabindex="-1">2. Isi WebDAV Configuration di ImgBed <a class="header-anchor" href="#_2-isi-webdav-configuration-di-imgbed" aria-label="Permalink to &quot;2. Isi WebDAV Configuration di ImgBed&quot;">​</a></h3><p>Kembali ke ImgBed dan tambahkan WebDAV channel:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL yang disediakan oleh <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>WebDAV username Anda.</td></tr><tr><td>Password</td><td>App password yang baru dibuat.</td></tr><tr><td>Authentication mode</td><td>Mulai dengan <code>Basic</code> untuk sebagian besar kasus.</td></tr><tr><td>Storage directory</td><td>Default adalah <code>imgbed</code>; Anda juga bisa memakai custom directory.</td></tr></tbody></table><p><img src="'+i+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="perilaku-upload-file-besar" tabindex="-1">Perilaku Upload File Besar <a class="header-anchor" href="#perilaku-upload-file-besar" aria-label="Permalink to &quot;Perilaku Upload File Besar&quot;">​</a></h2><p>WebDAV channel sekarang memakai real session-based chunked upload.</p><p>Small files di-upload sebagai satu complete file. Files lebih besar dari 64 MiB otomatis dipecah menjadi chunks sekitar 10 MiB dan di-upload ke remote chunk directory.</p><p>WebDAV service tidak perlu mendukung <code>partial update</code> atau offset-based writes. ImgBed tidak merge chunks menjadi satu large file di remote server. Sebaliknya, ImgBed menyimpan chunk manifest dan membaca chunks secara berurutan saat file diminta.</p><p>Dalam praktik:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB atau lebih kecil</td><td>Normal upload</td><td>Satu complete file</td></tr><tr><td>Lebih besar dari 64 MiB</td><td>Real session chunked upload</td><td>Chunk directory berisi beberapa chunk files</td></tr></tbody></table><p>Chunk directory hanya memengaruhi remote storage layout. File URL di ImgBed tidak berubah. Users tetap mengakses file lewat link <code>/file/...</code> asli.</p><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buka Upload Settings.</li><li>Klik Add Channel.</li><li>Pilih <code>WebDAV</code>.</li><li>Masukkan channel name yang mudah dikenali, misalnya <code>koofr</code>.</li><li>Masukkan WebDAV endpoint, misalnya <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Masukkan username dan password.</li><li>Biarkan authentication mode sebagai <code>Basic</code> secara default.</li><li>Biarkan storage directory sebagai <code>imgbed</code>, atau ubah ke directory Anda sendiri.</li><li>Klik Save.</li><li>Setelah save, cek channel card, query capacity jika tersedia, dan upload test file.</li></ol><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Memeriksa</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Setelah save, halaman Upload Settings harus menampilkan WebDAV channel card.</td></tr><tr><td>Channel enabled</td><td>Switch di kanan atas card seharusnya tetap on.</td></tr><tr><td>Credentials tersimpan</td><td>Detail view harus menampilkan Endpoint, username, authentication mode, dan storage directory.</td></tr><tr><td>Small file upload berjalan</td><td>Upload test image dan pastikan file muncul di WebDAV directory.</td></tr><tr><td>Large file rule berjalan</td><td>Files lebih besar dari 64 MiB memakai chunked upload dan membuat remote chunk directory.</td></tr><tr><td>Capacity query berjalan</td><td>Jika server mendukung capacity information, query akan menampilkan used dan total capacity.</td></tr></tbody></table><p><img src="'+n+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="mengapa-large-webdav-files-membuat-chunk-directory" tabindex="-1">Mengapa large WebDAV files membuat chunk directory? <a class="header-anchor" href="#mengapa-large-webdav-files-membuat-chunk-directory" aria-label="Permalink to &quot;Mengapa large WebDAV files membuat chunk directory?&quot;">​</a></h3><p>Ini adalah storage method saat ini untuk large files.</p><p>Files lebih besar dari 64 MiB tidak digabung menjadi satu large remote file. Files disimpan sebagai chunk directory. ImgBed merekam chunk manifest dan mengembalikan content lengkap dengan membaca chunks secara berurutan.</p><h3 id="jika-large-file-upload-gagal-apa-yang-perlu-dicek-dulu" tabindex="-1">Jika large file upload gagal, apa yang perlu dicek dulu? <a class="header-anchor" href="#jika-large-file-upload-gagal-apa-yang-perlu-dicek-dulu" aria-label="Permalink to &quot;Jika large file upload gagal, apa yang perlu dicek dulu?&quot;">​</a></h3><p>Cek Endpoint, username, password, dan storage directory terlebih dahulu. Lalu pastikan WebDAV service mengizinkan directory creation, file writing, dan file reading.</p><p>Jika capacity query gagal tetapi small file upload berjalan, server mungkin tidak mendukung atau membatasi capacity reporting. Itu belum tentu berarti upload tidak tersedia.</p><h3 id="authentication-mode-mana-yang-harus-digunakan" tabindex="-1">Authentication mode mana yang harus digunakan? <a class="header-anchor" href="#authentication-mode-mana-yang-harus-digunakan" aria-label="Permalink to &quot;Authentication mode mana yang harus digunakan?&quot;">​</a></h3><p>Mulai dengan <code>Basic</code>.</p><p>Jika server secara eksplisit membutuhkan digest authentication, gunakan <code>Digest</code>.</p><p>Jika tidak yakin, gunakan automatic negotiation.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Siapkan WebDAV endpoint, username, dan password</span></span>
<span class="line"><span>-&gt; Buka Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Pilih WebDAV</span></span>
<span class="line"><span>-&gt; Masukkan Endpoint / username / password</span></span>
<span class="line"><span>-&gt; Biarkan authentication mode sebagai Basic secara default</span></span>
<span class="line"><span>-&gt; Biarkan storage directory sebagai imgbed secara default</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Upload test file</span></span></code></pre></div>`,45)])])}const f=d(o,[["render",u]]);export{y as __pageData,f as default};
